from collections import defaultdict

def topological_sort(n, edges):
    def dfs(node):
        if node in visited:
            return visited[node]
        visited[node] = None
        for neighbor in graph[node]:
            if dfs(neighbor) is None:
                return None
        visited[node] = node
        return node

    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)

    visited = {}
    order = []

    for node in range(n):
        if dfs(node) is None:
            return []
        order.append(dfs(node))

    return order[::-1]
